@code {
    private string trackingNumber = string.Empty;
    private ShipmentDto? shipment;
    private string errorMessage = string.Empty;
    private bool isLoading;

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
        {
            await SearchShipment();
        }
    }

    private async Task SearchShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        isLoading = true;
        errorMessage = string.Empty;
        shipment = null;

        try
        {
            var response = await Http.GetAsync($"/api/shipments/track/{Uri.EscapeDataString(trackingNumber.Trim())}");
            if (response.IsSuccessStatusCode)
            {
                shipment = await response.Content.ReadFromJsonAsync<ShipmentDto>();
            }
            else
            {
                errorMessage = "Shipment not found. Please check the tracking number and try again.";
            }
        }
        catch
        {
            errorMessage = "An error occurred while searching. Please try again.";
        }
        finally
        {
            isLoading = false;
        }
    }

    private static string GetStatusBadgeClass(string status) => status switch
    {
        "Processing" => "bg-secondary",
        "In Transit" => "bg-primary",
        "Out for Delivery" => "bg-info text-dark",
        "Delivered" => "bg-success",
        "Delayed" => "bg-warning text-dark",
        _ => "bg-secondary"
    };
}
