@code {
    private List<ShipmentDto>? shipments;
    private string filterText = string.Empty;
    private string message = string.Empty;

    private IEnumerable<ShipmentDto> FilteredShipments =>
        shipments?.Where(s => string.IsNullOrEmpty(filterText)
            || s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase)) ?? [];

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        try
        {
            shipments = await Http.GetFromJsonAsync<List<ShipmentDto>>("/api/shipments");
        }
        catch
        {
            message = "Failed to load shipments.";
        }
    }

    private async Task UpdateStatus(ShipmentDto shipment, string newStatus)
    {
        if (shipment.Status == newStatus) return;

        var response = await Http.PutAsJsonAsync($"/api/shipments/{shipment.Id}/status",
            new UpdateShipmentStatusRequest { Status = newStatus });

        if (response.IsSuccessStatusCode)
        {
            shipment.Status = newStatus;
            message = $"Updated {shipment.TrackingNumber} to '{newStatus}'.";
        }
        else
        {
            message = $"Failed to update {shipment.TrackingNumber}.";
        }
    }

    private static string GetStatusBadgeClass(string status) => status switch
    {
        "Processing" => "bg-secondary",
        "In Transit" => "bg-primary",
        "Out for Delivery" => "bg-info text-dark",
        "Delivered" => "bg-success",
        "Delayed" => "bg-warning text-dark",
        _ => "bg-secondary"
    };
}
