@page "/dispatcher"
@using ShipmentTracker.Client.Models
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize(Roles = "Dispatcher")]
@inject HttpClient Http
@rendermode InteractiveAuto

<PageTitle>Dispatcher Dashboard</PageTitle>

<h1>Dispatcher Dashboard</h1>

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else if (!shipments.Any())
{
    <p>No shipments found.</p>
}
else
{
    <div class="mb-3">
        <input type="text" class="form-control" placeholder="Filter by destination..."
               @bind="filterText" @bind:event="oninput" />
    </div>

    <table class="table table-striped">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Shipped</th>
                <th>Est. Delivery</th>
                <th>Customer</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in FilteredShipments)
            {
                <tr>
                    <td>@shipment.TrackingNumber</td>
                    <td>@shipment.Origin</td>
                    <td>@shipment.Destination</td>
                    <td>
                        <span class="badge @GetStatusBadgeClass(shipment.Status)">
                            @shipment.Status
                        </span>
                    </td>
                    <td>@shipment.ShippedDate.ToString("MMM dd, yyyy")</td>
                    <td>@(shipment.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "—")</td>
                    <td>@shipment.CustomerEmail</td>
                    <td>
                        <select class="form-select form-select-sm" value="@shipment.Status"
                                @onchange="e => UpdateStatus(shipment, e.Value?.ToString()!)">
                            <option value="Processing">Processing</option>
                            <option value="In Transit">In Transit</option>
                            <option value="Out for Delivery">Out for Delivery</option>
                            <option value="Delivered">Delivered</option>
                            <option value="Delayed">Delayed</option>
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@if (!string.IsNullOrEmpty(message))
{
    <div class="alert alert-info mt-2">@message</div>
}

@code {
    private List<ShipmentDto>? shipments;
    private string filterText = string.Empty;
    private string message = string.Empty;

    private IEnumerable<ShipmentDto> FilteredShipments =>
        shipments?.Where(s => string.IsNullOrEmpty(filterText)
            || s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase)) ?? [];

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        try
        {
            shipments = await Http.GetFromJsonAsync<List<ShipmentDto>>("/api/shipments");
        }
        catch
        {
            message = "Failed to load shipments.";
        }
    }

    private async Task UpdateStatus(ShipmentDto shipment, string newStatus)
    {
        if (shipment.Status == newStatus) return;

        var response = await Http.PutAsJsonAsync($"/api/shipments/{shipment.Id}/status",
            new UpdateShipmentStatusRequest { Status = newStatus });

        if (response.IsSuccessStatusCode)
        {
            shipment.Status = newStatus;
            message = $"Updated {shipment.TrackingNumber} to '{newStatus}'.";
        }
        else
        {
            message = $"Failed to update {shipment.TrackingNumber}.";
        }
    }

    private static string GetStatusBadgeClass(string status) => status switch
    {
        "Processing" => "bg-secondary",
        "In Transit" => "bg-primary",
        "Out for Delivery" => "bg-info text-dark",
        "Delivered" => "bg-success",
        "Delayed" => "bg-warning text-dark",
        _ => "bg-secondary"
    };
}

