// Add additional endpoints required by the Identity /Account Razor components.
app.MapAdditionalIdentityEndpoints();

// Shipment API endpoints
var shipments = app.MapGroup("/api/shipments");

shipments.MapGet("/", async (ApplicationDbContext db) =>
{
    var list = await db.Shipments
        .OrderByDescending(s => s.ShippedDate)
        .Select(s => new ShipmentDto
        {
            Id = s.Id,
            TrackingNumber = s.TrackingNumber,
            Origin = s.Origin,
            Destination = s.Destination,
            Status = s.Status,
            ShippedDate = s.ShippedDate,
            EstimatedDelivery = s.EstimatedDelivery,
            CustomerEmail = s.CustomerEmail
        })
        .ToListAsync();
    return Results.Ok(list);
}).RequireAuthorization(policy => policy.RequireRole("Dispatcher"));

shipments.MapPut("/{id:int}/status", async (int id, UpdateShipmentStatusRequest request, ApplicationDbContext db) =>
{
    var shipment = await db.Shipments.FindAsync(id);
    if (shipment is null) return Results.NotFound();
    shipment.Status = request.Status;
    await db.SaveChangesAsync();
    return Results.Ok();
}).RequireAuthorization(policy => policy.RequireRole("Dispatcher"));

shipments.MapGet("/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
{
    var shipment = await db.Shipments
        .Where(s => s.TrackingNumber == trackingNumber)
        .Select(s => new ShipmentDto
        {
            Id = s.Id,
            TrackingNumber = s.TrackingNumber,
            Origin = s.Origin,
            Destination = s.Destination,
            Status = s.Status,
